mapper.select:
/* 설 명 : 게시판미열람수조회 */ SELECT SUM( CASE WHEN BBS.BBS_TYCD = 'NTC' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL_INQ_RCD IR WHERE IR.ATCL_ID = BA.ATCL_ID AND IR.VWER_ID = #{userId} ) THEN 1 ELSE 0 END ) AS NOTICE_UNREAD_CNT, /* 1. 공지사항미열람수 */ SUM( CASE WHEN BBS.BBS_TYCD = 'QNA' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL REPLY WHERE REPLY.UP_ATCL_ID = BA.ATCL_ID AND REPLY.DELYN = 'N' ) THEN 1 ELSE 0 END ) AS QNA_NOREPLY_CNT, /* 2. Qna미답변수 */ SUM( CASE WHEN BBS.BBS_TYCD = '1ON1' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL REPLY WHERE REPLY.UP_ATCL_ID = BA.ATCL_ID AND REPLY.DELYN = 'N' ) THEN 1 ELSE 0 END ) AS ONE_ON_ONE_NOREPLY_CNT, /* 3. 1대1미답변수 */ SUM( CASE WHEN BBS.BBS_TYCD = 'DATA' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL_INQ_RCD IR WHERE IR.ATCL_ID = BA.ATCL_ID AND IR.VWER_ID = #{userId} ) THEN 1 ELSE 0 END ) AS DATARM_UNREAD_CNT /* 4. 자료실미열람수 */ FROM TB_LMS_BBS_ATCL BA JOIN TB_LMS_BBS BBS ON BA.BBS_ID = BBS.BBS_ID AND BBS.DELYN = 'N'
AND BBS.SBJCT_ID = #{subjectId}
WHERE BA.DELYN = 'N'
